  }, "\uC678\uBD80 \uC608\uCE21 \uC2DC\uC2A4\uD15C (\uC7AC\uACE0\uAD00\uB9AC \uC2DC\uC2A4\uD15C\uACFC \uC8FC\uBB38 \uC11C\uBE0C\uB3C4\uBA54\uC778\uACFC \uD1B5\uD569\uB418\uC5B4 \uC788\uB294 \uC0C1\uD0DC)")))), mdx("p", null, "\uB9CC\uC57D \uC0C8\uB85C\uC6B4 \uD575\uC2EC \uB3C4\uBA54\uC778\uC744 \uCD94\uAC00\uD558\uAC70\uB098 \uBF51\uC544\uB0B4\uC57C \uD558\uB294 \uC0C1\uD669\uC774\uB77C\uBA74 \uBE44\uC988\uB2C8\uC2A4 \uC601\uC5ED\uC744 \uAD6C\uC131\uD558\uB294 \uB17C\uB9AC\uC801 \uC11C\uBE0C\uB3C4\uBA54\uC778\uACFC \uD1B5\uD569\uB41C \uC694\uAD6C\uB97C \uC774\uD574\uD558\uB294 \uAC83\uC774 \uD070 \uB3C4\uC6C0\uC774 \uB41C\uB2E4.\n\uC989, \uC704\uC5D0\uC11C \"\uD1B5\uD569\"\uC774 \uC5B4\uB5BB\uAC8C \uC774\uB8E8\uC5B4\uC838 \uC788\uB294 \uD655\uC778\uD558\uB294 \uAC83\uC740 \uD504\uB85C\uC81D\uD2B8 \uC2DC\uC791 \uC9C0\uC810\uC5D0\uC11C \uD30C\uC545\uC744 \uC704\uD55C \uC5F4\uC1E0\uB2E4."), mdx("p", null, "\uD55C \uAE30\uC5C5\uC758 \uBC14\uC6B4\uB514\uB4DC \uCEE8\uD14D\uC2A4\uD2B8\uAC00 \uC644\uC804\uD788 \uB3C5\uB9BD\uC801\uC77C \uC218\uB294 \uC5C6\uB2E4. \uB2E4\uB978 \uBAA8\uB378\uACFC \uD568\uAED8 \uC791\uC6A9\uD558\uBA74\uC11C \uD1B5\uD569 \uAD00\uACC4\uAC00 \uD544\uC218\uC801\uC774\uAE30 \uB54C\uBB38\uC774\uB2E4.\n\uC774 \uD1B5\uD569\uC5D0\uB294 \uC5B8\uC81C\uB098 \uD2B9\uC815 \uC720\uD615\uC758 \uAD00\uACC4\uAC00 \uC5F0\uAD00\uB418\uC5B4 \uC788\uC73C\uBA70, \uCEE8\uD14D\uC2A4\uD2B8 \uB9F5\uC5D0\uC11C \uB354 \uC790\uC138\uD788 \uB2E4\uB8E8\uAC8C \uB41C\uB2E4."), mdx("p", null, "\uC704\uC758 \uC804\uC790 \uC0C1\uAC70\uB798 \uC2DC\uC2A4\uD15C\uC744 \uBCF4\uBA74 \uC6A9\uC5B4\uC640 \uC758\uBBF8\uAC00 \uCDA9\uB3CC\uD560 \uAC00\uB2A5\uC131\uC774 \uB9E4\uC6B0 \uB192\uB2E4. \uC608\uB97C \uB4E4\uC5B4 \uACE0\uAC1D\uC774\uB77C\uB294 \uC6A9\uC5B4\uB294 \uCDA9\uB3CC\uC744 \uC77C\uC73C\uD0AC\uD150\uB370, \uBD84\uBA85 \uCE74\uD0C8\uB85C\uADF8\uB97C \uC0B4\uD544 \uB54C\uC640 \uC8FC\uBB38\uC744 \uD560 \uB54C\uC758\n\uACE0\uAC1D\uC740 \uC11C\uB85C \uB2E4\uB978 \uC758\uBBF8\uB97C \uAC00\uC9C0\uAE30 \uB54C\uBB38\uC774\uB2E4. \uCE74\uD0C8\uB85C\uADF8\uB97C \uC0B4\uD544 \uB54C\uC758 \uACE0\uAC1D\uC740 \uC774\uC804\uC758 \uAD6C\uB9E4, \uCDA9\uC131\uB3C4, \uAC00\uB2A5\uD55C \uC81C\uD488, \uD560\uC778, \uBC30\uC1A1 \uC635\uC158 \uC774\uB77C\uB294 \uCEE8\uD14D\uC2A4\uD2B8\uC5D0\uC11C \uC0AC\uC6A9\uB418\uC9C0\uB9CC,\n\uC8FC\uBB38 \uC2DC\uC758 \uACE0\uAC1D\uC740 \uBC30\uC1A1\uC9C0 \uC8FC\uC18C, \uCCAD\uAD6C\uC9C0 \uC8FC\uC18C, \uCD1D \uAE08\uC561, \uC9C0\uBD88 \uBC29\uBC95 \uB4F1\uC758 \uCEE8\uD14D\uC2A4\uD2B8\uC5D0\uC11C \uC0AC\uC6A9\uB41C\uB2E4."), mdx("p", null, "\uC11C\uBE0C\uB3C4\uBA54\uC778\uC774 \uD56D\uC0C1 \uD070 \uD06C\uAE30\uC640 \uAE30\uB2A5\uC744 \uAC00\uC9C4 \uD2B9\uBCC4\uD55C \uBAA8\uB378\uC744 \uD3EC\uD568\uD558\uB294 \uAC74 \uC544\uB2C8\uB2E4. \uB54C\uB860 \uC11C\uBE0C \uB3C4\uBA54\uC778\uC740 \uACE0\uC720\uC758 \uD575\uC2EC \uB3C4\uBA54\uC778\uC758 \uC77C\uBD80\uAC00 \uC544\uB2CC \uC77C\uB828\uC758 \uC54C\uACE0\uB9AC\uC998\uACFC \uAC19\uC740 \uAC04\uB2E8\uD55C \uD615\uD0DC\uC77C \uC218\uB3C4 \uC788\uB2E4."), mdx("p", null, "\uC774\uB807\uB4EF \uD558\uB098\uC758 \uBC14\uC6B4\uB514\uB4DC \uCEE8\uD14D\uC2A4\uD2B8 \uC548\uC5D0\uB294 \uC5EC\uB7EC \uC11C\uBE0C\uB3C4\uBA54\uC778, \uD639\uC740 \uB2E8 \uD558\uB098\uC758 \uC11C\uBE0C\uB3C4\uBA54\uC778\uC774 \uC874\uC7AC\uD560 \uC218 \uC788\uB294\uB370 \uD2B9\uC815 \uC6A9\uC5B4\uC758 \uCDA9\uB3CC \uBC29\uC9C0\uB098 \uC678\uBD80 \uD1B5\uD569\uC744 \uC6D0\uD65C\uD788 \uD558\uAE30 \uC704\uD574\uC11C\uB77C\uB3C4\n\uC11C\uBE0C\uB3C4\uBA54\uC778\uACFC \uBC14\uC6B4\uB514\uB4DC \uCEE8\uD14D\uC2A4\uD2B8\uAC00 \uD65C\uC6A9\uB418\uC5B4\uC57C \uD55C\uB2E4."), mdx("h3", null, "\uD575\uC2EC \uB3C4\uBA54\uC778\uC5D0 \uC9D1\uC911\uD558\uAE30"), mdx("ul", null, mdx("li", {
