uD544\uC694\uB294 \uC5C6\uB2E4\uB294 \uC774\uC57C\uAE30\uB2E4."), mdx("h2", null, "\uC65C \uC804\uB7B5\uC801 \uC124\uACC4\uAC00 \uC5C4\uCCAD\uB098\uAC8C \uD544\uC218\uC801\uC778\uAC00"), mdx("p", null, "\uC804\uC220\uC801 \uC124\uACC4\uC5D0\uB9CC \uC9D1\uC911\uD558\uAC8C \uB418\uBA74 \uB354 \uD070 \uBE44\uC804\uC744 \uAC00\uB824 \uC624\uD788\uB824 \uC124\uACC4\uC758 \uACE0\uD1B5\uC744 \uB290\uB07C\uAC8C \uB41C\uB2E4. \uC608\uB97C \uB4E4\uC5B4 \uD611\uC5C5 \uCEE8\uD14D\uC2A4\uD2B8\uC548\uC5D0 \uB2E4\uC74C\uACFC \uAC19\uC774 \uBAA8\uB378\uB4E4\uC774 \uC0C1\uD638 \uC5F0\uAD00\uB418\uC5B4 \uC788\uB2E4\uACE0 \uD558\uC790."), mdx("ul", null, mdx("li", {
